const today = new Date().toISOString().slice(0, 10);
const stamp = Date.now();
const runId = `N8N-STOCK-BATCH-${stamp}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, itemGroup: `${runId} Nhóm batch`, warehouseName: `${runId} Batch WH`, itemCode: `${runId} Hàng batch Đặc biệt`, batchId: `${runId}-BATCH-001`, receiptQty: 5, issueQty: 2, rate: 29 } }];

const ctx = $node['Build Batch Context'].json;
const receipt = $node['Submit Batch Receipt'].json;
const issue = $node['Submit Batch Issue'].json;
const bin = $('Verify Batch Bin').all().map(i => i.json);
const sle = $('Verify Batch SLE').all().map(i => i.json);
const expectedQty = ctx.receiptQty - ctx.issueQty;
const text = JSON.stringify({ ctx, receipt, issue, bin, sle });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const hasReceiptLedger = sle.some(row => row.voucher_no === $node['Create Batch Receipt'].json.name && Number(row.actual_qty) === ctx.receiptQty && Number(row.qty_after_transaction) === ctx.receiptQty);
const hasIssueLedger = sle.some(row => row.voucher_no === $node['Create Batch Issue'].json.name && Number(row.actual_qty) === -ctx.issueQty && Number(row.qty_after_transaction) === expectedQty);
const status = Number(receipt.docstatus) === 1 && Number(issue.docstatus) === 1 && Number(bin[0]?.actual_qty) === expectedQty && hasReceiptLedger && hasIssueLedger ? 'passed' : 'failed';
return [{ json: { status, runId: ctx.runId, item: $node['Create Batch Item'].json.name, batch: $node['Create Batch'].json.name, warehouse: $node['Create Batch Warehouse'].json.name, receipt: $node['Create Batch Receipt'].json.name, receiptDocstatus: receipt.docstatus, issue: $node['Create Batch Issue'].json.name, issueDocstatus: issue.docstatus, binActualQty: bin[0]?.actual_qty, batchLedgerRows: sle.length, batchLedgerActualQty: sle.map(row => ({ voucher_no: row.voucher_no, batch_no: row.batch_no, actual_qty: row.actual_qty, qty_after_transaction: row.qty_after_transaction })), batchTrackingNote: 'ERPNext v16 stores batch detail in Serial and Batch Bundle/Entry; DB verification records the exact batch_no.', securityFindings } }];
